import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import axios from 'axios';

function UASTLChart() {
    const d3Container = useRef(null);

    useEffect(() => {
        let svg;
        let width = d3Container.current.clientWidth;
        let height = d3Container.current.clientHeight;
        let margin = { top: 24, right: 24, bottom: 32, left: 56 };
        let chartW = width - margin.left - margin.right;
        let chartH = height - margin.top - margin.bottom;
        const subplotH = chartH / 6;

        // 清空
        d3.select(d3Container.current).selectAll('*').remove();

        // 取得資料
        axios.get('http://localhost:3001/api/uastl').then(res => {
            const data = res.data;
            if (!data || data.length === 0) return;
            // 解析欄位
            const keys = Object.keys(data[0]);
            const n = data.length;
            // 動態取得季節成分數量
            const seasonalKeys = keys.filter(k => k.startsWith('seasonal') && k.endsWith('_mean'));
            const L = seasonalKeys.length;
            // 子圖標題
            const titles = ['Input Data', 'Trend Component', ...seasonalKeys.map((k, i) => `Seasonal Component ${i + 1}`), 'Residual Component'];
            // 對應欄位
            const meanKeys = ['input_mean', 'trend_mean', ...seasonalKeys, 'residual_mean'];
            const stdKeys = ['input_std', 'trend_std', ...seasonalKeys.map(k => k.replace('_mean', '_std')), 'residual_std'];
            const corrKeys = ['corr_input', 'corr_trend', ...seasonalKeys.map(k => k.replace('_mean', '')), 'corr_residual'];
            const sampleKeys = [1, 2, 3].map(i => [
                `sample${i}_input`, `sample${i}_trend`, ...seasonalKeys.map((k, idx) => `sample${i}_seasonal${idx + 1}`), `sample${i}_residual`
            ]);

            // SVG
            svg = d3.select(d3Container.current)
                .append('svg')
                .attr('width', width)
                .attr('height', height);

            // 每個子圖
            meanKeys.forEach((key, i) => {
                const g = svg.append('g')
                    .attr('transform', `translate(${margin.left},${margin.top + i * subplotH})`);
                const vals = data.map(d => +d[key]);
                const stds = data.map(d => +d[stdKeys[i]]);
                const y = d3.scaleLinear()
                    .domain([d3.min(vals, (d, j) => d - 2.6 * stds[j]), d3.max(vals, (d, j) => d + 2.6 * stds[j])]).nice()
                    .range([subplotH - 32, 0]);
                const x = d3.scaleLinear()
                    .domain([0, n - 1])
                    .range([0, chartW]);
                // 信賴區間陰影
                g.append('path')
                    .datum(vals.map((m, j) => [x(j), y(m - 2.6 * stds[j])]))
                    .attr('fill', 'none')
                    .attr('stroke', 'none')
                    .attr('id', `lower99_${i}`);
                g.append('path')
                    .datum(vals.map((m, j) => [x(j), y(m + 2.6 * stds[j])]))
                    .attr('fill', 'none')
                    .attr('stroke', 'none')
                    .attr('id', `upper99_${i}`);
                g.append('polygon')
                    .attr('points', vals.map((m, j) => `${x(j)},${y(m - 2.6 * stds[j])}`).join(' ') + ' ' + vals.slice().reverse().map((m, j) => `${x(n - 1 - j)},${y(m + 2.6 * stds[n - 1 - j])}`).join(' '))
                    .attr('fill', '#6ec6ff44');
                g.append('polygon')
                    .attr('points', vals.map((m, j) => `${x(j)},${y(m - 0.67 * stds[j])}`).join(' ') + ' ' + vals.slice().reverse().map((m, j) => `${x(n - 1 - j)},${y(m + 0.67 * stds[n - 1 - j])}`).join(' '))
                    .attr('fill', '#ffd18066');
                // 樣本路徑
                sampleKeys.forEach((sks, si) => {
                    const sample = data.map(d => +d[sks[i]]);
                    g.append('path')
                        .datum(sample)
                        .attr('fill', 'none')
                        .attr('stroke', d3.schemeCategory10[si + 2])
                        .attr('stroke-width', 1)
                        .attr('opacity', 0.7)
                        .attr('d', d3.line()
                            .x((d, idx) => x(idx))
                            .y(d => y(d))
                        );
                });
                // 均值線
                g.append('path')
                    .datum(vals)
                    .attr('fill', 'none')
                    .attr('stroke', '#ff6a00')
                    .attr('stroke-width', 2)
                    .attr('d', d3.line()
                        .x((d, idx) => x(idx))
                        .y(d => y(d))
                    );
                // 紅藍相關性條
                const corr = data.map(d => +d[corrKeys[i]]);
                const corrColor = d3.scaleLinear().domain([-1, 0, 1]).range(['#3b4cc0', '#fff', '#b40426']);
                g.selectAll('.corrbar')
                    .data(corr)
                    .enter()
                    .append('rect')
                    .attr('class', 'corrbar')
                    .attr('x', (d, idx) => x(idx))
                    .attr('y', subplotH - 28)
                    .attr('width', chartW / n)
                    .attr('height', 8)
                    .attr('fill', d => corrColor(d));
                // 標題
                g.append('text')
                    .attr('x', 0)
                    .attr('y', -8)
                    .attr('fill', '#fff')
                    .attr('font-size', 16)
                    .text(titles[i]);
                // Y軸
                g.append('g')
                    .call(d3.axisLeft(y).ticks(4))
                    .selectAll('text').attr('fill', '#fff');
                // X軸（只畫在最後一個子圖）
                if (i === meanKeys.length - 1) {
                    g.append('g')
                        .attr('transform', `translate(0,${subplotH - 32})`)
                        .call(d3.axisBottom(x).ticks(10).tickFormat(idx => idx))
                        .selectAll('text').attr('fill', '#fff');
                }
                // Hover提示
                g.append('rect')
                    .attr('width', chartW)
                    .attr('height', subplotH - 32)
                    .attr('fill', 'transparent')
                    .on('mousemove', function (event) {
                        const [mx] = d3.pointer(event);
                        const idx = Math.round(x.invert ? x.invert(mx) : mx / chartW * n);
                        if (idx < 0 || idx >= n) return;
                        d3.select(`#hoverline_${i}`).remove();
                        g.append('line')
                            .attr('id', `hoverline_${i}`)
                            .attr('x1', x(idx))
                            .attr('x2', x(idx))
                            .attr('y1', 0)
                            .attr('y2', subplotH - 32)
                            .attr('stroke', '#fff')
                            .attr('stroke-width', 1)
                            .attr('stroke-dasharray', '3 2');
                    })
                    .on('mouseleave', function () {
                        d3.select(`#hoverline_${i}`).remove();
                    });
            });
        });
    }, []);

    return (
        <div style={{ position: 'relative' }}>
            <h2 style={{ color: '#ff6a00' }}>UASTL 分解圖</h2>
            <div ref={d3Container} style={{ width: '100%', height: '500px', background: '#181a1b', borderRadius: '12px', boxShadow: '0 2px 12px #ff6a0022', overflow: 'hidden', position: 'relative' }}>
                {/* D3 UASTL分解圖會渲染在這裡 */}
            </div>
        </div>
    );
}

export default UASTLChart;
